using System.Collections;
using UnityEngine;

// ─── Acções NPC — Sementes ─────────────────────────────────────────────────
//
// Conjunto de acções para dar, tirar e mostrar Sementes em eventos de NPC,
// com suporte a animação de contagem na HUD.
//
// ── Animação ──────────────────────────────────────────────────────────────
//
// As acções "Animated" animam o número de Sementes na HUD de uma forma
// visualmente satisfatória:
//   - Duração máxima: 1 segundo (Action_GiveSementesAnimated.maxDuration).
//   - Velocidade proporcional à diferença: 5 sementes → contagem lenta;
//     100 sementes → contagem rápida (nunca ultrapassa 1 segundo).
//   - A animação usa PlayerProgress.FireSeedsAnimationTick(int) — a HUD de
//     Sementes deve subscrever a PlayerProgress.SeedsAnimationTick para
//     mostrar o valor animado.
//   - O saldo REAL só é alterado no final da animação (via GiveSementes).
//
// ── Silenciosas ───────────────────────────────────────────────────────────
//
// As acções "Silent" alteram o saldo sem disparar eventos, sem animação
// e sem actualização visual da HUD. Úteis para:
//   - Penalizações discretas que o designer não quer mostrar ao player.
//   - Ajustes de balanceamento durante cutscenes longas.
//   - Combinação com Action_SavePlayerSnapshot (restaurar depois sem o player saber).

/// <summary>
/// Mostra o número actual de Sementes do player.
///
/// Esta acção força o HUD de Sementes a actualizar para o valor real actual,
/// dispara SeedsChanged (torna a contagem visível se estiver escondida) e
/// espera "displayDuration" segundos para o designer poder usar numa sequência
/// de diálogo antes de chamar uma das acções de dar/tirar.
///
/// Uso típico: antes de Action_GiveSementesAnimated, para que o player veja
/// quantas sementes tem antes de as perder ou ganhar.
/// </summary>
[System.Serializable]
public class Action_ShowSementes : NpcAction
{
    [Tooltip("Tempo (segundos) que a acção aguarda após actualizar o HUD — permite que o player veja o valor antes da próxima acção. 0 = sem espera.")]
    [Min(0f)] public float displayDuration = 0.5f;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null) yield break;

        // Força o HUD a mostrar o valor real actual (refresca qualquer
        // display obsoleto e torna o contador visível se estava escondido).
        progress.RefreshSeedsDisplay();

        if (displayDuration > 0f)
            yield return NpcActionUtil.Wait(displayDuration);
    }
}

/// <summary>
/// Dá (amount > 0) ou tira (amount < 0) Sementes com animação de contagem na HUD.
///
/// A HUD de Sementes deve subscrever <see cref="PlayerProgress.SeedsAnimationTick"/>
/// para mostrar o número a animar. O saldo real só é alterado no final da animação.
///
/// Parâmetros:
/// - amount: número de Sementes a dar (positivo) ou tirar (negativo).
/// - maxDuration: duração máxima da animação (padrão: 1s).
/// - Se amount == 0, nenhuma animação ocorre.
/// </summary>
[System.Serializable]
public class Action_GiveSementesAnimated : NpcAction
{
    [Tooltip("Sementes a dar (positivo) ou tirar (negativo). O saldo nunca desce abaixo de 0.")]
    public int amount = 5;

    [Tooltip("Duração máxima da animação, em segundos. A animação pode ser mais curta para quantidades pequenas.")]
    [Min(0.05f)] public float maxDuration = 1f;

    [Tooltip("Número mínimo de frames de animação (evita que diferenças de 1 semente sejam instantâneas — mínimo 4 frames recomendado).")]
    [Min(1)] public int minFrames = 4;

    public override IEnumerator Execute(NpcController npc)
    {
        var progress = PlayerProgress.Instance;
        if (progress == null || amount == 0) yield break;

        int fromValue = progress.sementes;
        int toValue = Mathf.Max(0, fromValue + amount);
        int delta = Mathf.Abs(toValue - fromValue);

        if (delta == 0) yield break;  // já no limite (ex: tirar de 0)

        // Duração proporcional à diferença, mas sempre ≤ maxDuration.
        // Fórmula: começa com 0.1s de base + 0.04s por unidade (chega ao
        // máximo de 1s com ~22 sementes de diferença; acima disso comprime).
        float naturalDuration = 0.1f + delta * 0.04f;
        float duration = Mathf.Min(naturalDuration, maxDuration);

        float elapsed = 0f;
        int lastDisplayed = fromValue;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float t = Mathf.SmoothStep(0f, 1f, Mathf.Clamp01(elapsed / duration));
            int display = Mathf.RoundToInt(Mathf.Lerp(fromValue, toValue, t));

            if (display != lastDisplayed)
            {
                lastDisplayed = display;
                progress.FireSeedsAnimationTick(display);
            }

            yield return null;
        }

        // Garante que o display final mostra o valor exacto.
        if (lastDisplayed != toValue)
            progress.FireSeedsAnimationTick(toValue);

        // Aplica o saldo real (dispara SeedsChanged → HUD confirma valor final).
        progress.GiveSementes(amount);
    }
}

/// <summary>
/// Adiciona Sementes sem animação e sem actualização visual da HUD.
///
/// O saldo é alterado internamente mas SeedsChanged NÃO é disparado —
/// a HUD continua a mostrar o valor anterior até que outra acção (ex:
/// Action_ShowSementes) ou o próximo pickup/evento actualize o display.
///
/// Útil para:
/// - Compensações em background que o player não deve notar imediatamente.
/// - Ajustes durante cutscenes longas (a HUD actualiza naturalmente depois).
/// </summary>
[System.Serializable]
public class Action_GiveSementesSilent : NpcAction
{
    [Tooltip("Sementes a adicionar (positivo) ou remover (negativo). Saldo nunca desce abaixo de 0.")]
    public int amount = 5;

    public override IEnumerator Execute(NpcController npc)
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.GiveSementesSilent(amount);
        yield break;
    }
}

/// <summary>
/// Remove Sementes com animação de contagem na HUD (atalho semântico para
/// Action_GiveSementesAnimated com amount negativo — mais claro no Inspector).
///
/// Se o player não tiver sementes suficientes, o saldo vai até 0 (nunca negativo).
/// </summary>
[System.Serializable]
public class Action_TakeSementesAnimated : NpcAction
{
    [Tooltip("Sementes a retirar. Saldo nunca desce abaixo de 0.")]
    [Min(1)] public int amount = 5;

    [Tooltip("Duração máxima da animação de contagem descendente.")]
    [Min(0.05f)] public float maxDuration = 1f;

    public override IEnumerator Execute(NpcController npc)
    {
        // Delega para GiveSementesAnimated com amount negativo.
        var inner = new Action_GiveSementesAnimated
        {
            amount = -amount,
            maxDuration = maxDuration
        };
        yield return inner.Execute(npc);
    }
}

/// <summary>
/// Remove Sementes sem animação e sem actualização visual da HUD.
/// </summary>
[System.Serializable]
public class Action_TakeSementesSilent : NpcAction
{
    [Tooltip("Sementes a retirar silenciosamente. Saldo nunca desce abaixo de 0.")]
    [Min(1)] public int amount = 5;

    public override IEnumerator Execute(NpcController npc)
    {
        if (PlayerProgress.Instance != null)
            PlayerProgress.Instance.GiveSementesSilent(-amount);
        yield break;
    }
}
